value.string:
{
 "type": "object",
 "description": "Table data with metadata and rows",
 "properties": {
 "count": {
 "type": "integer",
 "description": "Total number of records"
 },
 "start": {
 "type": "integer",
 "description": "Starting index of the current page"
 },
 "end": {
 "type": "integer",
 "description": "Ending index of the current page"
 },
 "portal_type": {
 "type": "string",
 "description": "Portal type identifier"
 },
 "rows": {
 "type": "array",
 "description": "List of rows, where each row is a dictionary mapping column names to values",
 "items": {
 "type": "object",
 "description": "A single row of data",
 "patternProperties": {
 "^.*$": {
 "type": ["string", "number", "boolean", "null"],
 "description": "Column value"
 }
 },
 "additionalProperties": true
 }
 }
 },
 "required": ["count", "start", "end", "portal_type", "rows"],
 "additionalProperties": false
 }

{
 "additionalProperties": false,
 "required": [
 "portal_type_id"
 ],
 "type": "object",
 "properties": {
 "sort_on": {
 "type": "array",
 "items": {
 "type": "array",
 "minItems": 2,
 "maxItems": 2,
 "items": {
 "type": "string"
 }
 },
 "default": [["uid", "ascending"]],
 "description": "Sort order specification.\n\nA list of [column, direction] pairs where column is any filterable column name (as shown in MCP_getPortalTypeSchema) and direction is either 'ascending' or 'descending'. Results are sorted by the first pair, then the second for ties, etc.\n\nDefault: [['uid', 'ascending']].\n\nExample: [['last_name', 'ascending'], ['first_name', 'ascending']]"
 },
 "column_list": {
 "items": {
 "type": "string"
 },
 "type": "array",
 "default": [],
 "description": "Specifies which columns to include in the result.\n\nProvide a list of column names (using the human-readable titles as shown in MCP_getPortalTypeSchema).\n\nIf not provided, default columns are used. Use MCP_getPortalTypeSchema first to discover all available columns and identify which ones are marked as 'default'.\n\nExample: ['Title', 'Creation Date', 'State']"
 },
 "portal_type_id": {
 "type": "string",
 "description": "The ID/name of the portal type to get data of.\n\nUse MCP_listPortalTypes first to see all available portal type IDs and their descriptions.\n\nExamples: 'Task Report', 'Sale Order', 'Person'."
 },
 "filters": {
 "additionalProperties": {
 "type": "string"
 },
 "type": "object",
 "default": {},
 "description": "Dictionary of filters to apply, mapping column names (strings) to filter values (strings).\n\nUse the human-readable column titles as shown in MCP_getPortalTypeSchema. Only columns marked as 'filterable': true in the schema can be used. Supports % as wildcard character for partial matching (e.g., 'Smith%' for names starting with Smith, '%report%' for values containing 'report'). Both keys and values must be strings.\n\nExample: {'State': 'confirmed', 'Title': 'Project%'}"
 },
 "page": {
 "type": "integer",
 "default": 0,
 "description": "The page index for pagination (0-based). Each page contains at most 100 documents. The first page is 0. If the requested page exceeds the total number of pages (based on total items and page_size), an empty list will be returned. Check the total_count and total_pages in the response to determine valid page ranges."
 }
 }
 }
